/**
 * Monorepo detection + sparsePaths advisory — shared by the WorktreeCreate
 * provisioner (#2335) and the worktree lifecycle logger. Extracted from
 * worktree-lifecycle-logger.ts so both consumers share one implementation.
 */

import type { HookContext } from '../types.js';
import { writeWorktreeAdvisory } from './worktree-advisory.js';
import { existsSync, readdirSync, readFileSync } from 'node:fs';
import { join } from 'node:path';

/** Heuristic: repos with many top-level dirs are likely monorepos. */
const MONOREPO_DIR_THRESHOLD = 15;

/** Monorepo signals: workspace config files */
const MONOREPO_MARKERS = [
  'pnpm-workspace.yaml',
  'lerna.json',
  'nx.json',
  'rush.json',
  'turbo.json',
];

/** Read `worktree.sparsePaths` from project settings (CC 2.1.76+ key). */
export function getSparsePaths(projectDir: string): string[] | null {
  const settingsPath = join(projectDir, '.claude', 'settings.json');
  if (!existsSync(settingsPath)) return null;
  try {
    const settings = JSON.parse(readFileSync(settingsPath, 'utf8'));
    const paths = settings?.worktree?.sparsePaths;
    if (Array.isArray(paths) && paths.length > 0 && paths.every(p => typeof p === 'string')) {
      return paths;
    }
  } catch {
    /* fall through */
  }
  return null;
}

/**
 * Detect if the project is a monorepo and count top-level directories.
 * Fast — single readdir, no recursion.
 */
export function detectMonorepo(projectDir: string): { isMonorepo: boolean; topDirCount: number } {
  const hasMarker = MONOREPO_MARKERS.some(m => existsSync(join(projectDir, m)));

  let hasWorkspaces = false;
  const pkgPath = join(projectDir, 'package.json');
  if (existsSync(pkgPath)) {
    try {
      const pkg = JSON.parse(readFileSync(pkgPath, 'utf8'));
      hasWorkspaces = Array.isArray(pkg.workspaces) || typeof pkg.workspaces === 'object';
    } catch { /* ignore parse errors */ }
  }

  let topDirCount = 0;
  try {
    for (const entry of readdirSync(projectDir, { withFileTypes: true })) {
      if (entry.isDirectory() && !entry.name.startsWith('.') && entry.name !== 'node_modules') {
        topDirCount++;
      }
    }
  } catch { /* ignore readdir errors */ }

  return {
    isMonorepo: hasMarker || hasWorkspaces || topDirCount >= MONOREPO_DIR_THRESHOLD,
    topDirCount,
  };
}

/**
 * Write the deferred sparsePaths advisory (consumed by
 * prompt/worktree-advisory-consumer on the next UserPromptSubmit) when the
 * project is a monorepo without sparsePaths configured.
 */
export function maybeEmitMonorepoAdvisory(
  projectDir: string,
  name: string,
  ctx: HookContext,
  hookName: string,
): void {
  if (getSparsePaths(projectDir)) return; // already configured

  const { isMonorepo, topDirCount } = detectMonorepo(projectDir);
  if (!isMonorepo) return;

  const advisory =
    `⚡ **Monorepo detected on worktree "${name}"** (${topDirCount} top-level dirs). ` +
    'Consider configuring `worktree.sparsePaths` in `.claude/settings.json` to speed up worktree creation. ' +
    'Example: `{ "worktree": { "sparsePaths": ["src/", "packages/core/", "tests/"] } }` — ' +
    'only those directories will be checked out in worktrees (CC 2.1.76+).';
  const wrote = writeWorktreeAdvisory(advisory, name, projectDir);
  ctx.log(
    hookName,
    wrote
      ? `Monorepo (${topDirCount} dirs) without sparsePaths — advisory deferred to next prompt`
      : `Monorepo advisory write failed for worktree "${name}" — falling back to ctx.log only`,
  );
}
